var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"이런 걸 인간들은 반항기라고 부르더라. 시간이 많이 흐르긴 했나 봐.","JPN":"人間って、こういうのを反抗期って呼ぶらしいよ。いつの間にかだいぶ時間が経ってたんだね。","ENG":"So this is what humans call \\"the rebellious phase\\"... It appears that a long time has passed.","TWN":"這就是人類所謂的叛逆期，都已經過這麼久啦？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"참 희한해. 말이 통하는 나는 미움 받고, 말이 안 통하던 너는 받아 주고.","JPN":"おかしいよね。言葉が通じる私は嫌われたのに、言葉が通じなかったあなたは受け入れられてさ。","ENG":"Isn't it strange? How come they despise me when I can get along with them, but accept you when you can't even understand them?","TWN":"真稀奇，能溝通的我被討厭，卻接受無法溝通的你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"내 위장용 코디가 그렇게 티나나 하면 그것도 아닌데~","JPN":"変装した時のコーディネートが下手ってわけでもないと思うのに～","ENG":"It's not like my disguise was that obvious, is it?","TWN":"而且我的造型偽裝得那麼好～"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"네 그런 점이 거리를 두게 만드는 원인이라고 생각한 적은 없나?","JPN":"お前のそういうところが遠ざけられる原因だと思ったことはないのか？","ENG":"Haven't you ever thought that's what keeps you at their arm's length?","TWN":"你有沒有想過，這就是讓我和你產生距離的原因？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이. 인간들은 원래 날것 그대로를 싫어하는걸.","JPN":"ええ～人間って元々ありのままが嫌いなんだもん。","ENG":"Oh, please. You know how humans hate seeing things for what they are.","TWN":"哎呀，人類本來就討厭原本的樣子。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"처음부터 종 자체가 달라서 문제야. 난 그냥 그렇다고 믿을래.","JPN":"最初から種が違うのが問題なんだよ。そうだって信じることにする。","ENG":"It's because we're of different races to begin with. Or at least, that's what I'd like to believe.","TWN":"打從一開始，問題就出在種類不同。我寧願相信是那樣。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"……먼저 가서 기다리고 있어라.","JPN":"……先に行って待ってろ。","ENG":"…You go first and wait for me there.","TWN":"……你先去等我。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"내가 너를 물어뜯을 수 있게 되었을 때, 다시 찾아가겠다.","JPN":"私がお前を噛みちぎれるようになった時、また訪ねよう。","ENG":"I'll come back to you when I'm able to bite you off.","TWN":"等到我能咬住你的時候，會再去找你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐흥. 그냥 여기서 평생 인간들이랑 지내셔.","JPN":"ふふん。ここで人間たちと一生暮らしなさいよ。","ENG":"Hehe. No, you should just stay here with the humans for the rest of your life.","TWN":"哼哼，你就一輩子和人類在這裡生活吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내</color>가 되어 봤자 두려움만 살 뿐이라는 건, 너도 이제 알 거 아냐.","JPN":"<color=#ffd34c>私</color>になっても怖がられるだけだってこと、あなたももう知ってるでしょ？","ENG":"I know that you must have realized by now that becoming <color=#ffd34c>me</color> will only invoke fear in them.","TWN":"你現在不是也知道，就算成為<color=#ffd34c>我</color>，也只能活在恐懼裡。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"참 딱하기도 하지. 겨우 스쳐 지나가는 인간들의 원망을 꾸역꾸역 삼키고 있었으니.","JPN":"可哀想よね。すれ違っただけの人間の恨みを無理やり飲み込んでいたなんて。","ENG":"You were swallowing your resentment for them all this time. What a pity.","TWN":"真慘，好不容易才吞掉人類的怨恨。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"기억해? 예전의 레비아탄은 무적이었던 거 있지?","JPN":"覚えてる？　昔のレヴィアタンは無敵だったってこと。","ENG":"Do you still remember? When Leviathan was invincible?","TWN":"你還記得嗎？以前的利維坦是無敵的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"둘이서 하나라 외롭지 않아. 아무 생각 없이 사냥만 즐기면 그만이었던 거야.","JPN":"二人で一人だから寂しくなかった。ただ何も考えずに楽しく狩るだけでよかったもん。","ENG":"We were one and never lonely. All we did was enjoy the thrill of the hunt.","TWN":"因為二個就是一體，所以一點都不孤單。什麼都不用想，只要盡情享受狩獵就好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"인간들에게 의존해야 하는 삶 따위는, 레비아탄에게 언빌리버블한 일이라구.","JPN":"人間に頼らなければいけない人生なんて、レヴィアタンにはアンビリバボーなことだよ。","ENG":"But having to rely on humans... That's something unthinkable for Leviathan.","TWN":"必須依賴人類的生活，對利維坦而言簡直不可思議。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"그래도 나는 지금이 더 낫다.","JPN":"それでも私は今の方がいい。","ENG":"Still, I like this better.","TWN":"但我更喜歡現在。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어째서?","JPN":"なんで？","ENG":"But why?","TWN":"為什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"이 아이가 나와 마시멜로를 나눠 먹었으니까.","JPN":"この子と一緒にマシュマロを食べたから。","ENG":"Because this child shares her marshmallows with me.","TWN":"因為她會跟我分享棉花糖。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_ReinforcedA_NULL","text":{"KOREA":"하아아아아아아!!","JPN":"はああああああっ！！","ENG":"HAAAAA!!","TWN":"啊啊啊啊啊啊！！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L22_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"……치. 좋겠다, 부끄럼쟁이.","JPN":"……ち。いいなぁ、恥ずかしがり屋。","ENG":"...Tch! Good for you, my shy little sister.","TWN":"……嘖，真羨慕你，討厭！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 시민 여러분께 안내 말씀드립니다.</color>","JPN":"<color=#ffd34c>グラウンド・ワンの市民の皆さんにご案内します。</color>","ENG":"<color=#ffd34c>Attention all Ground One citizens.</color>","TWN":"<color=#ffd34c>通知G1的市民。</color>"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되면서 대균열에 출몰한 괴생명체가 물러나기 시작했습니다.</color>","JPN":"<color=#ffd34c>ただいま、連鎖的な現実崩壊現象の進行が鈍化し、大亀裂に出没した怪生命体が退却しはじめました。</color>","ENG":"<color=#ffd34c>The chain of reality collapses have started to slow down, and the mysterious creature that appeared in the Grand Dimension Crevice has begun to retreat.</color>","TWN":"<color=#ffd34c>目前連鎖現實崩壞現象已經趨緩下來，在大峽谷出沒的怪物開始撤退。</color>"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>각 태스크포스는 전투 태세를 유지한 상태로 지시를 기다려 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>各タスクフォースは戦闘態勢を維持したまま、指示をお待ちください。</color>","ENG":"<color=#ffd34c>To all TASKFORCE, please maintain battle positions until further notice.</color>","TWN":"<color=#ffd34c>請各個特遣勢力維持戰鬥狀態，等候進一步指示。</color>"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>반복합니다. 현재, 연쇄적 현실 붕괴 현상의 진행이 둔화되었으며……</color>","JPN":"<color=#ffd34c>繰り返します。ただいま、連鎖的な現実崩壊現象の進行が鈍化し……</color>","ENG":"<color=#ffd34c>I repeat, the chain of reality collapses have started to slow down...</color>","TWN":"<color=#ffd34c>再重複一次。目前連鎖現實崩壞現象已經趨緩下來……</color>"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아! 오셨군요! 여기, 여기예요!","JPN":"あ！　来た！　こっち、こっちです！","ENG":"Oh, you're here! Over here!","TWN":"終於來啦！這裡，我在這裡！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"신고자 본인 되십니까? 괴한이 인질을 어디로 끌고 갔습니까?","JPN":"通報者ご本人ですか？　不審者は人質をどこに連れて行きましたか。","ENG":"Are you the one who reported the incident? Where did they take the hostages?","TWN":"是你報警的嗎？可疑人士將人質帶到哪裡？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저희 회사 사무실로 가야 한다고 했어요. 그런데……","JPN":"私の会社の事務室に行くって言ってました。でも……","ENG":"They said they were headed to our office. But...","TWN":"說是要去我們公司辦公室。不過……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"방금 전에, 건물이 폭삭 무너져 내려서…….","JPN":"さっき、建物が完全に崩れてしまって……","ENG":"Just a moment ago, the building collapsed and...","TWN":"剛才大樓突然崩塌……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"……이런 맙소사.","JPN":"……まずい。","ENG":"Oh dear...","TWN":"……我的天。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"구급대에다 붕괴 현장이라고 연락해! 매몰자들을 구조해야 한다!","JPN":"救急隊に崩壊現場だと連絡しろ！　埋没された人を救わなければ！","ENG":"Contact the paramedics and tell them the building collapsed! We need to rescue those who are trapped underneath it!","TWN":"通知救難隊，說這裡是崩塌現場！要救援被埋住的人！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"어떤가? 걱정했던 것 치고는 아주 성공적으로 치워 버린 것 같은데.","JPN":"どうかね？　心配した割にはよい感じに片付いたようだが。","ENG":"What do you think? I think it was rather successful to destroy, everything given.","TWN":"如何？雖然很擔心，但似乎有成功拆除呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L44_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그러니까 치워 버리겠다던 게…… 건물 얘기였다고?","JPN":"つまり片付くと言ったのは……建物の話だったの？","ENG":"When you said \\"destroy\\"... You meant the building?","TWN":"所以你說要拆除的……是指大樓嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"물론이지, 마담. 그럼 대체 뭐라고 생각했나?","JPN":"当たり前さ、マダム。ではいったい何だと思ったんだい？","ENG":"Of course, madam. What else would I have been talking about?","TWN":"當然囉，夫人。不然你以為是什麼？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그야 당연히……!!","JPN":"それはもちろん……！！","ENG":"Of course, I assumed...!!","TWN":"當然是……！！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……아니, 관두자. 너랑 얘기할 때마다 내가 바보가 되는 기분이니까.","JPN":"……いえ、やめましょう。あなたと話すたびに私がバカになっていく気がするもの。","ENG":"...Forget it. I feel like I'm becoming an idiot just talking with you.","TWN":"……不，就這樣吧，每次和你說話，都讓我覺得自己像傻瓜。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그나저나 이젠 말해 줄 때도 된 것 같은데?","JPN":"それよりそろそろ話してくれない？","ENG":"By the way, don't you think it's time to tell me?","TWN":"話說回來，你現在該告訴我了吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"대체 이 모든 짓거리에 무슨 목적이 있는 건지 말이야.","JPN":"いったいこのすべてに何の目的があるのか。","ENG":"About why you're doing all of this, I mean.","TWN":"你做這些事的目的到底是什麼？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"의외로군. 아직 못 알아차리고 있었나?","JPN":"意外だな。まだ気付いていないのか？","ENG":"I'm surprised you haven't figured it out yet.","TWN":"真意外，你到現在還看不出來嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마담이라면 진작에 내 의도를 이해했을 거라고 생각했는데.","JPN":"マダムならとっくに私の意図を理解していると思ったのだが。","ENG":"I was certain you would've understood my intentions by now, madam.","TWN":"我還以為夫人應該早就明白我的心思。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"세상에서 버림받은 아이들을 모아 세상과 싸울 수 있다는 아름답고도 헛된 꿈을 심어 주는 마담이라면 말이지.","JPN":"世界から捨てられた子供たちを集めて、世界と戦えるという美しくも無駄な夢を与えているマダムならね。","ENG":"Well, if you are the madam who gathers abandoned children and instills a beautiful but illusory dream of fighting the world in them, that is.","TWN":"畢竟夫人能把被世界遺棄的孩子聚集起來，為他們編織一個可以跟世界對抗，這樣美好又虛妄的夢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"높이 평가해 줘서 참 고맙구나. 애늙은이.","JPN":"高く評価してくれてうれしいわ。ませガキさん。","ENG":"Thank you for thinking so highly of me, you old soul.","TWN":"謝謝你給我這麼高的評價，少年老成先生。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"하지만 너 같은 미치광이랑 동류 취급 받는 건 매우 불쾌하니까 그냥 닥치고 묻는 말에나 대답해 주면 좋겠어.","JPN":"でもあなたのような狂人と同類扱いされるのはとても不愉快だから、黙って質問に答えてほしいわ。","ENG":"However, I'm offended to be treated like a lunatic, the same as you. So, if you will, please just shut up and answer my question.","TWN":"不過我很不開心，和你這個瘋子被視為同類。麻煩你閉上嘴，只要回答我的問題就好。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"미치광이라…….","JPN":"狂人か……","ENG":"A lunatic...","TWN":"瘋子嗎……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"이 세상은 거대하고 차가운 기계와도 같지.","JPN":"この世界は巨大で冷たい機械も同然だ。","ENG":"This world is like a massive, cold machine.","TWN":"這個世界就像一台冷冰冰的大型機器。"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그리고 기계에게 있는 건 오직 원인과 결과 뿐, 거기에 정 따위는 없어. ","JPN":"そしてその機械にあるのはただ原因と結果のみ、そこに情なんてない。 ","ENG":"And within that machine, there is no emotion, only the calculation of cause and effect. ","TWN":"對機器而言就只有原因和結果，沒有感情之類的元素。"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하지만 인간은……","JPN":"だが、人間は……","ENG":"But humans...","TWN":"但是人類……"},"stage":{"bg":"MS_904","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"오직 인간만은 자명한 진실에서 눈을 돌려 존재하지 않는 꿈을 쫓기도 한다네.","JPN":"人間だけは当然の真実から目を背け、存在していない夢を追ったりする。","ENG":"Only humans turn their backs on reality and chase after an unattainable dream.","TWN":"只有人類才會對顯而易見的真相視而不見，追求根本就不存在的夢想。"},"stage":{"bg":"MS_904","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇다면 누군가는 세상을 대신해서 그 꿈을 이루어 줘도 되지 않을까?","JPN":"なら誰かはその世界に代わってその夢を叶えてあげてもいいのではないか？","ENG":"Then wouldn't someone have to step up to make that dream come true?","TWN":"若是如此，是不是有個人可以替世界實現這個夢想？"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아직 이 세상에 한 줌의 온기가…… 희망이 남아 있다는 꿈을 꿀 수 있게 말이야.","JPN":"まだこの世界に少しの温もりが……希望が残っているという夢を見ることができるように。","ENG":"To show that the world is still worth living... and give hope for them to dream.","TWN":"讓人可以夢想這個世界還存有一絲溫暖……與希望。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그 작은 기적이, 가장 차가운 기계에 의해 만들어졌다는 걸 모두가 알 필요는 없겠지.","JPN":"その小さな奇跡が、もっとも冷たい機械によって作られたということをみんなが知る必要はないだろう。","ENG":"However, they don't need to know that their \\"little miracle\\" was made by the hands of a cold and calculating machine.","TWN":"不過大家不需要知道，那麼小的奇蹟，是由最冰冷的機器創造出來的。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……지금 무슨 헛소리를 하는 거니?","JPN":"……何をくだらないこと言ってるのかしら。","ENG":"...What kind of nonsense is that?","TWN":"……你在胡言亂語什麼？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"저 애송이 경찰과 테러리스트 아가씨의 인생을 뒤흔들어 버린 것도.","JPN":"あのひよっこ警察官とテロリストのお嬢さんの人生を揺さぶったのも。","ENG":"So you traumatized that young officer and the terrorist girl.","TWN":"打亂那個年輕警察和恐怖份子女孩的人生，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"평의회와 베로니카를 이용한 것도.","JPN":"評議会とベロニカを利用したのも。","ENG":"Used Veronica and the Council.","TWN":"利用評議會和貝洛妮卡，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"심지어는 저 마왕이니 뭐니 하는 괴물들까지 가지고 놀면서 바란다는 게…….","JPN":"しかもあの魔王か何かの化け物まで出してきて望んだことというのが……","ENG":"And even entertained those demon-whatevers all just...","TWN":"甚至將那個魔王還是什麼的怪物玩弄於鼓掌之間……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그저 우리 인생에 희망이 있기를 바라서라고? ","JPN":"ただ私たちの人生に希望があってほしいからですって？ ","ENG":"So that you could bring hope into our lives? ","TWN":"全都只是希望我們的人生有希望？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"정확해, 마담.","JPN":"そのとおりだ、マダム。","ENG":"Exactly, madam.","TWN":"正確，夫人。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그것이 바로 내가 아직 작동되고 있는 이유라네.","JPN":"それこそが私がまだ作動している理由なのだよ。","ENG":"That is why I'm still here.","TWN":"這就是我還在運作的理由。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"……옛날에, 널 생각보다 다정한 남자라고 한 적이 있었지.","JPN":"……昔、あなたを思ったより優しい男って言ったことがあったわね。","ENG":"You know, I used to think you were more considerate than I had thought.","TWN":"……先前，我曾說過沒想到你是個重感情的男人對吧。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그 말은 취소야. ","JPN":"その言葉、取り消すわ。 ","ENG":"But I take that back. ","TWN":"這句話我收回。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"기계 수집가 녀석의 말투를 따라하고 싶진 않지만…… 넌 정말 미쳐버린 깡통이야. ","JPN":"機械収集家の口調を真似したくはないけど……あなたは本当に狂ったボロ缶ね。 ","ENG":"I don't want to sound like Machine Collector, but... you're just a crazy tin can. ","TWN":"雖然不想模仿機械收藏家那傢伙的語氣……但你真的是個瘋狂的鐵桶。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"미칠 수 있다는 건 인간의 특권이지. 기계인 나로서는 부러울 뿐이라네.","JPN":"狂うことができるというのは人間の特権さ。機械である私としては羨ましいかぎりだ。","ENG":"To go crazy is a privilege only humans have. As a machine, I can only be envious.","TWN":"可以發瘋是人類的特權。身為機器的我只有羡慕的份。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아무튼, 돌은 던져졌네.","JPN":"とにかく、石は投げられた。","ENG":"Anyway, the pebble has been tossed into the water.","TWN":"總之，石頭已經扔了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"바람도, 파도도 없는 허수공간이라는 고요한 바다에 던져진 레비아탄이라는 돌은…… ","JPN":"風も、波もない虚数空間という静かな海に投げられたレヴィアタンという石は…… ","ENG":"The Leviathan pebble, which has been thrown into a silent ocean known as the imaginary space with no wind or waves... ","TWN":"將那顆名叫利維坦的石頭，扔在無風無浪，稱之為虛數空間的寂靜大海裡……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"자신의 본질에 걸맞게 거대한 풍랑을 만들어 낼 테지.","JPN":"自分の本質に似合う巨大な風浪を作り出すだろう。","ENG":"Will cause a massive storm befitting her own essence.","TWN":"她應該會引起符合她本質的巨浪吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그리고 그 풍랑이 다시금 잔잔한 파문이 되어 기적의 끝자락에 도착할 거야.","JPN":"そしてその風浪がまた静かな波紋になり、奇跡の先へとたどり着くはずだ。","ENG":"And once the storm subsides and waves become ripples, we will be on the verge of a miracle.","TWN":"然後那些風浪又會重新成為漣漪，抵達奇蹟的盡頭。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"기적이라고……?","JPN":"奇跡……？","ENG":"A miracle...?","TWN":"你說奇蹟……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"MS_1004","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"잿더미만 남은 불씨가 최후의 빛을 피워 올릴 수 있게 하는 것.","JPN":"灰に残った火種が最後に炎を上げることができるようにすること。","ENG":"The one thing that will allow the ember’s ashes to rise to the final light.","TWN":"讓只剩下灰燼的火苗燃起最後的光芒。"},"stage":{"bg":"MS_1004","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그것이 내가, 이 세상을 살아가는 자들에게 선물할 기적일세.","JPN":"それが、私がこの世界で生きる者たちに贈る奇跡だ。","ENG":"This is... the miracle I gift to everyone living in this world.","TWN":"這就是，我送給活在這世上的人的奇蹟。"},"stage":{"bg":"MS_1004","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};